import android.content.Context
import android.content.SharedPreferences

class AuthenticationManager(context: Context) {
    private val sharedPreferences: SharedPreferences = context.getSharedPreferences("auth_prefs", Context.MODE_PRIVATE)
    private val AUTH_TOKEN_KEY = "auth_token"
    private val USER_ID_KEY = "user_id"

    var isAuthenticated: Boolean
        get() = authToken.isNotEmpty()

    val authToken: String
        get() = sharedPreferences.getString(AUTH_TOKEN_KEY, "") ?: ""

    val userId: Int
        get() = sharedPreferences.getInt(USER_ID_KEY, -1)

    fun saveAuthTokenAndUserId(token: String, id: Int) {
        val editor = sharedPreferences.edit()
        editor.putString(AUTH_TOKEN_KEY, token)
        editor.putInt(USER_ID_KEY, id)
        editor.apply()
    }

    fun clearAuthData() {
        val editor = sharedPreferences.edit()
        editor.remove(AUTH_TOKEN_KEY)
        editor.remove(USER_ID_KEY)
        editor.apply()
    }
}